const resp = ($.steps.scrapePage.response && $.steps.scrapePage.response.data) ? $.steps.scrapePage.response.data : {};
const html = resp.html || resp.rawHtml || '';
const md = resp.markdown || '';
const links = resp.links || [];

// Technical extraction
const titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
const metaDescMatch = html.match(/<meta[^>]*name=["']description["'][^>]*content=["']([^"']+)["']/i);
const h1s = md.match(/^# .+$/gm) || [];
const h2s = md.match(/^## .+$/gm) || [];
const h3s = md.match(/^### .+$/gm) || [];
const imgCount = (html.match(/<img /gi) || []).length;
const imgNoAlt = (html.match(/<img(?![^>]*alt=["'][^"']+["'])[^>]*>/gi) || []).length;
const formCount = (html.match(/<form/gi) || []).length;
const buttonCount = (html.match(/<button/gi) || []).length;
const inputCount = (html.match(/<input/gi) || []).length;
const videoCount = (html.match(/<video|youtube|vimeo/gi) || []).length;
const wordCount = md.split(/\s+/).length;
const hasSchema = html.includes('application/ld+json');
const hasViewport = html.includes('viewport');
const hasHttps = $.input.url.startsWith('https');
const hasSocialProof = /testimonial|review|rating|trust|customer|client/i.test(md);
const hasPricing = /pricing|price|\$|cost|plan|tier/i.test(md);
const hasFAQ = /faq|frequently asked|common questions/i.test(md);
const hostname = new URL($.input.url).hostname;
const internalLinks = links.filter(l => { try { return new URL(l).hostname === hostname; } catch(e) { return false; } }).length;
const externalLinks = links.length - internalLinks;

const ctaPatterns = md.match(/(?:get started|sign up|try free|start free|book a demo|schedule|contact us|buy now|add to cart|subscribe|download|learn more|request|claim)/gi) || [];

return {
  title: titleMatch ? titleMatch[1].trim() : '(missing)',
  metaDescription: metaDescMatch ? metaDescMatch[1].trim() : '(missing)',
  h1s: h1s.map(h => h.replace(/^# /, '')),
  h2s: h2s.map(h => h.replace(/^## /, '')),
  h3Count: h3s.length,
  wordCount,
  images: imgCount,
  imagesNoAlt: imgNoAlt,
  forms: formCount,
  buttons: buttonCount,
  inputs: inputCount,
  videos: videoCount,
  totalLinks: links.length,
  internalLinks,
  externalLinks,
  hasSchema,
  hasViewport,
  hasHttps,
  hasSocialProof,
  hasPricing,
  hasFAQ,
  ctaCount: ctaPatterns.length,
  ctaTexts: [...new Set(ctaPatterns.map(c => c.toLowerCase()))],
  contentPreview: md.slice(0, 3000)
};

const p = $.steps.extractPageData.output;
const url = $.input.url;
const context = $.input.businessContext || '';

let prompt = 'You are a senior conversion rate optimization (CRO) consultant. Perform a comprehensive landing page audit of the page data below. Be specific, actionable, and reference actual elements from the page.\n\n';
prompt += 'PAGE URL: ' + url + '\n';
if (context) prompt += 'BUSINESS CONTEXT: ' + context + '\n';
prompt += '\n';

prompt += '=== TECHNICAL PROFILE ===\n';
prompt += 'Title: ' + p.title + '\n';
prompt += 'Meta description: ' + p.metaDescription + '\n';
prompt += 'H1 tags: ' + (p.h1s.length ? p.h1s.join(' | ') : '(none)') + '\n';
prompt += 'H2 tags: ' + (p.h2s.length ? p.h2s.join(' | ') : '(none)') + '\n';
prompt += 'H3 count: ' + p.h3Count + '\n';
prompt += 'Word count: ' + p.wordCount + '\n';
prompt += 'Images: ' + p.images + ' total, ' + p.imagesNoAlt + ' missing alt\n';
prompt += 'Forms: ' + p.forms + ' | Buttons: ' + p.buttons + ' | Input fields: ' + p.inputs + '\n';
prompt += 'Videos: ' + p.videos + '\n';
prompt += 'Links: ' + p.totalLinks + ' (' + p.internalLinks + ' internal, ' + p.externalLinks + ' external)\n';
prompt += 'CTA count: ' + p.ctaCount + ' | CTA texts found: ' + p.ctaTexts.join(', ') + '\n';
prompt += 'Schema markup: ' + (p.hasSchema ? 'Yes' : 'No') + '\n';
prompt += 'Mobile viewport: ' + (p.hasViewport ? 'Yes' : 'No') + '\n';
prompt += 'HTTPS: ' + (p.hasHttps ? 'Yes' : 'No') + '\n';
prompt += 'Social proof present: ' + (p.hasSocialProof ? 'Yes' : 'No') + '\n';
prompt += 'Pricing visible: ' + (p.hasPricing ? 'Yes' : 'No') + '\n';
prompt += 'FAQ section: ' + (p.hasFAQ ? 'Yes' : 'No') + '\n\n';

prompt += '=== PAGE CONTENT ===\n';
prompt += p.contentPreview + '\n\n';

prompt += '=== INSTRUCTIONS ===\n';
prompt += 'Use Slack mrkdwn format: *bold* (NOT **bold**), _italic_, :emoji:, numbered lists. No markdown tables. No # headings.\n\n';
prompt += 'Return ONLY valid JSON with these exact keys:\n';
prompt += '{\n';
prompt += '  "overallScore": 0-100,\n';
prompt += '  "executiveSummary": "2-3 sentence overview of the page\'s conversion potential",\n';
prompt += '  "heroSection": { "score": 0-10, "headline": "analysis of headline effectiveness", "subheadline": "analysis", "recommendations": ["specific fixes"] },\n';
prompt += '  "copyAnalysis": { "score": 0-10, "clarity": "is the value prop clear?", "persuasion": "emotional triggers and benefit-focused language", "recommendations": ["specific fixes"] },\n';
prompt += '  "ctaAnalysis": { "score": 0-10, "currentCTAs": "what CTAs exist and their effectiveness", "placement": "are CTAs above fold and repeated?", "recommendations": ["specific fixes"] },\n';
prompt += '  "trustSignals": { "score": 0-10, "existing": "what trust elements are present", "missing": "what should be added", "recommendations": ["specific fixes"] },\n';
prompt += '  "uxAndDesign": { "score": 0-10, "pageStructure": "flow and visual hierarchy", "mobileReadiness": "mobile optimization signals", "recommendations": ["specific fixes"] },\n';
prompt += '  "seo": { "score": 0-10, "findings": "meta tags, headings, schema analysis", "recommendations": ["specific fixes"] },\n';
prompt += '  "topFixes": ["#1 highest-impact fix", "#2", "#3", "#4", "#5"],\n';
prompt += '  "quickWins": ["changes that take less than 1 hour"]\n';
prompt += '}\n';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { overallScore: 0, executiveSummary: raw.slice(0, 2000), topFixes: [], text: raw }; }

const ai = $.steps.parseAI.output;
const url = $.input.url;
const score = ai.overallScore || 0;

// Score emoji
let scoreEmoji = ':red_circle:';
if (score >= 70) scoreEmoji = ':large_green_circle:';
else if (score >= 40) scoreEmoji = ':large_yellow_circle:';

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Landing Page CRO Analysis', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: scoreEmoji + ' *Overall Score: ' + score + '/100*\n' + (ai.executiveSummary || '') + '\n\n*Page:* <' + url + '|' + url + '>' } });
blocks.push({ type: 'divider' });

// Section scores
const sections = [
  { key: 'heroSection', label: 'Hero Section', emoji: ':dart:' },
  { key: 'copyAnalysis', label: 'Copy & Messaging', emoji: ':pencil2:' },
  { key: 'ctaAnalysis', label: 'Call-to-Action', emoji: ':point_right:' },
  { key: 'trustSignals', label: 'Trust Signals', emoji: ':shield:' },
  { key: 'uxAndDesign', label: 'UX & Design', emoji: ':art:' },
  { key: 'seo', label: 'SEO', emoji: ':mag:' }
];

sections.forEach(sec => {
  const data = ai[sec.key];
  if (!data) return;
  let text = sec.emoji + ' *' + sec.label + '* — ' + (data.score || 0) + '/10\n';
  // Add the main analysis fields (skip score and recommendations)
  Object.keys(data).forEach(k => {
    if (k === 'score' || k === 'recommendations') return;
    text += '*' + k.charAt(0).toUpperCase() + k.slice(1).replace(/([A-Z])/g, ' $1') + ':* ' + data[k] + '\n';
  });
  if (data.recommendations && data.recommendations.length) {
    text += '*Recommendations:*\n';
    data.recommendations.forEach((r, i) => { text += (i + 1) + '. ' + r + '\n'; });
  }
  // Slack section text limit is ~3000 chars
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text.slice(0, 2900) } });
  blocks.push({ type: 'divider' });
});

// Top fixes
if (ai.topFixes && ai.topFixes.length) {
  let fixText = ':rotating_light: *Top 5 Highest-Impact Fixes*\n';
  ai.topFixes.forEach((f, i) => { fixText += (i + 1) + '. ' + f + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: fixText } });
  blocks.push({ type: 'divider' });
}

// Quick wins
if (ai.quickWins && ai.quickWins.length) {
  let qwText = ':zap: *Quick Wins (< 1 hour)*\n';
  ai.quickWins.forEach((q, i) => { qwText += (i + 1) + '. ' + q + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: qwText } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Analyzed via Firecrawl + Claude AI | CRO score: ' + score + '/100' }] });

const fallback = 'Landing Page Analysis: ' + url + ' scored ' + score + '/100';

return { blocks, fallback };
